// Tijdvak afleiden uit datum-tijd: ochtend / middag / avond
function tijdvak(datumString) {
  if (!datumString) return '';
  const t = String(datumString);
  if (!t.includes('T')) return '';
  const uur = parseInt(t.split('T')[1].slice(0, 2), 10);
  if (isNaN(uur)) return '';
  if (uur < 12) return 'Ochtend';
  if (uur < 17) return 'Middag';
  return 'Avond';
}

function dagenSinds(datumString) {
  const nu = new Date();
  const dan = new Date(datumString);
  return Math.floor((nu - dan) / (1000 * 60 * 60 * 24));
}

function formatDatum(d) {
  const date = new Date(d);
  return date.toLocaleDateString('nl-NL', { day: '2-digit', month: '2-digit', year: 'numeric' });
}

// Compacte datum: "12 mei" of "12 mei '25" als ander jaar
function formatDatumKort(d) {
  if (!d) return '';
  const date = new Date(d);
  if (isNaN(date.getTime())) return '';
  const huidigJaar = new Date().getFullYear();
  if (date.getFullYear() === huidigJaar) {
    return date.toLocaleDateString('nl-NL', { day: 'numeric', month: 'short' });
  }
  return date.toLocaleDateString('nl-NL', { day: 'numeric', month: 'short' }) + " '" + String(date.getFullYear()).slice(-2);
}

function formatDatumTijd(d) {
  if (!d) return '';
  const date = new Date(d);
  // Toon alleen tijd als 'm aanwezig is (anders middernacht = oude datum-only)
  const heeftTijd = String(d).includes('T') || String(d).includes(':');
  if (!heeftTijd) return formatDatum(d);
  return date.toLocaleDateString('nl-NL', { day: '2-digit', month: '2-digit', year: 'numeric' }) + ' ' + date.toLocaleTimeString('nl-NL', { hour: '2-digit', minute: '2-digit' });
}

function escapeHtml(s) {
  if (s === null || s === undefined) return '';
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

