// =================== DATUM HELPERS (LOKALE TIJD) ===================
// We werken in de app altijd met het formaat 'YYYY-MM-DDTHH:MM' (16 chars) = lokale tijd, geen UTC.
// Dit is hetzelfde formaat dat <input type="datetime-local"> gebruikt.

// Format een Date object als 'YYYY-MM-DDTHH:MM' in LOKALE tijd (geen UTC!)
function datumNaarInput(d) {
  const dt = d instanceof Date ? d : new Date(d);
  if (isNaN(dt.getTime())) return '';
  const y = dt.getFullYear();
  const m = String(dt.getMonth() + 1).padStart(2, '0');
  const day = String(dt.getDate()).padStart(2, '0');
  const h = String(dt.getHours()).padStart(2, '0');
  const min = String(dt.getMinutes()).padStart(2, '0');
  return `${y}-${m}-${day}T${h}:${min}`;
}

// Maak een datum-sleutel YYYY-MM-DD op basis van LOKALE tijdzone (niet UTC!)
function lokaleDatumSleutel(d) {
  const dt = d instanceof Date ? d : new Date(d);
  if (isNaN(dt.getTime())) return '';
  return `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}-${String(dt.getDate()).padStart(2, '0')}`;
}

// Converteer een datum-waarde uit de database naar het LOKALE 'YYYY-MM-DDTHH:MM' formaat.
// Input kan zijn: 'YYYY-MM-DDTHH:MM:SS+TZ', ISO Z, 'YYYY-MM-DD HH:MM:SS+TZ' (PostgreSQL), of plat 'YYYY-MM-DD'.
function dbNaarInput(dbDatum) {
  if (!dbDatum) return '';
  const s = String(dbDatum);
  // Alleen datum (geen tijd) ongewijzigd laten
  if (!s.includes('T') && !s.includes(' ')) return s;
  // Heeft timezone-info? Detecteer ALLE varianten: Z, +HH, +HHMM, +HH:MM, -varianten
  const heeftTz = s.endsWith('Z') || /[+-]\d{2}(:?\d{2})?$/.test(s);
  if (heeftTz) {
    const d = new Date(s);
    if (!isNaN(d.getTime())) {
      return datumNaarInput(d);  // lokale tijd via getHours/getMinutes
    }
  }
  // Geen timezone of niet-parseerbaar - knip op 16 chars en zet spatie om naar T.
  return s.replace(' ', 'T').slice(0, 16);
}

// =================== BON DATA HELPERS ===================
// Bongegevens worden "verstopt" in het opmerking-veld (geen Supabase wijziging nodig).
// Formaat: vrije opmerking + speciale tag met JSON aan het eind.
// De tag is onzichtbaar voor de gebruiker; de app parsed hem eruit.

const BON_TAG_START = '\n\n<!--BONDATA:';
const BON_TAG_EINDE = ':BONDATA-->';

// Haal de bongegevens uit een opmerking-string. Retourneert { opmerking, bon }.
function splitOpmerkingEnBon(volledigeTekst) {
  if (!volledigeTekst) return { opmerking: '', bon: null };
  const tekst = String(volledigeTekst);
  const startIdx = tekst.indexOf(BON_TAG_START);
  if (startIdx === -1) return { opmerking: tekst, bon: null };
  const eindeIdx = tekst.indexOf(BON_TAG_EINDE, startIdx);
  if (eindeIdx === -1) return { opmerking: tekst, bon: null };
  const opmerking = tekst.slice(0, startIdx);
  const jsonRaw = tekst.slice(startIdx + BON_TAG_START.length, eindeIdx);
  try {
    const bon = JSON.parse(jsonRaw);
    return { opmerking, bon };
  } catch (e) {
    return { opmerking: tekst, bon: null };
  }
}

// Combineer een gewone opmerking met bongegevens tot een opmerking-string.
function combineerOpmerkingEnBon(opmerking, bonData) {
  const opm = String(opmerking || '');
  if (!bonData || Object.keys(bonData).length === 0) return opm;
  const schoon = {};
  Object.keys(bonData).forEach(k => {
    const v = bonData[k];
    if (v !== '' && v !== null && v !== undefined) schoon[k] = v;
  });
  if (Object.keys(schoon).length === 0) return opm;
  return opm + BON_TAG_START + JSON.stringify(schoon) + BON_TAG_EINDE;
}

