function leesFotoAlsDataUrl(file, maxBreedte = 900, kwaliteit = 0.62) {
  return new Promise((resolve, reject) => {
    if (!file) return resolve(null);
    const reader = new FileReader();
    reader.onerror = () => reject(new Error('Foto kon niet gelezen worden.'));
    reader.onload = () => {
      const img = new Image();
      img.onerror = () => reject(new Error('Foto kon niet verwerkt worden.'));
      img.onload = () => {
        const schaal = Math.min(1, maxBreedte / img.width);
        const canvas = document.createElement('canvas');
        canvas.width = Math.max(1, Math.round(img.width * schaal));
        canvas.height = Math.max(1, Math.round(img.height * schaal));
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/jpeg', kwaliteit));
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}

// Converteer database-rij (snake_case) naar app-formaat (camelCase)
function vanDb(rij) {
  // Split opmerking in normale opmerking + bongegevens
  const { opmerking, bon } = splitOpmerkingEnBon(rij.opmerking);
  return {
    id: rij.id,
    aangemaakt: rij.aangemaakt,
    datum: dbNaarInput(rij.datum),
    monteur: rij.monteur || '',
    opdrachtgever: rij.opdrachtgever || '',
    adres: rij.adres || '',
    plaats: rij.plaats || '',
    typeMelding: rij.type_melding || '',
    locatie: rij.locatie || '',
    oorzaak: rij.oorzaak || '',
    opgelost: rij.opgelost || '',
    reparatieNodig: rij.reparatie_nodig || '',
    urgentie: rij.urgentie || 'Normaal',
    uitvoering: rij.uitvoering || '',
    statusStoring: rij.status_storing || 'Nieuw',
    statusReparatie: rij.status_reparatie || 'Te plannen',
    geplandeDatum: dbNaarInput(rij.geplande_datum) || '',
    opmerking: opmerking,
    historie: rij.historie || [],
    prijsregels: rij.prijsregels || [],
    // Particuliere bongegevens (uit opmerking gesplit, alleen aanwezig bij Particulier)
    klantNaam: (bon && bon.klantNaam) || '',
    telefoon: (bon && bon.telefoon) || '',
    email: (bon && bon.email) || '',
    betalingMethode: (bon && bon.betalingMethode) || '',
    bonBedrag: (bon && bon.bonBedrag) || '',
    bonOpmerking: (bon && bon.bonOpmerking) || '',
    factuurStatus: (bon && bon.factuurStatus) || 'Niet gefactureerd',
    fotos: (bon && Array.isArray(bon.fotos)) ? bon.fotos : [],
  };
}

// Converteer app-formaat naar database-rij
function naarDb(s) {
  // Combineer opmerking + bongegevens (alleen bij Particulier)
  let opmerkingVoorDb = s.opmerking || null;
  if (s.opdrachtgever === 'Particulier') {
    const bonData = {
      klantNaam: s.klantNaam,
      telefoon: s.telefoon,
      email: s.email,
      betalingMethode: s.betalingMethode,
      bonBedrag: s.bonBedrag,
      bonOpmerking: s.bonOpmerking,
      factuurStatus: s.factuurStatus,
      fotos: Array.isArray(s.fotos) ? s.fotos : [],
    };
    opmerkingVoorDb = combineerOpmerkingEnBon(s.opmerking || '', bonData) || null;
  }
  return {
    datum: s.datum,
    monteur: s.monteur,
    opdrachtgever: s.opdrachtgever,
    adres: s.adres,
    plaats: s.plaats,
    type_melding: s.typeMelding || null,
    locatie: s.locatie || null,
    oorzaak: s.oorzaak || null,
    opgelost: s.opgelost || null,
    reparatie_nodig: s.reparatieNodig || null,
    urgentie: s.urgentie || 'Normaal',
    uitvoering: s.uitvoering || null,
    status_storing: s.statusStoring || 'Nieuw',
    status_reparatie: s.statusReparatie || 'Te plannen',
    geplande_datum: s.geplandeDatum || null,
    opmerking: opmerkingVoorDb,
    historie: s.historie || [],
    prijsregels: s.prijsregels || [],
  };
}

// =================== STORAGE HELPERS ===================
function leesJson(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch (e) {
    console.warn('Lokale opslag kon niet gelezen worden:', e);
    return fallback;
  }
}

function schrijfJson(key, value) {
  localStorage.setItem(key, JSON.stringify(value));
}

async function supabaseRequest(path, opties = {}) {
  const response = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
    ...opties,
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      ...(opties.headers || {}),
    },
  });

  const tekst = await response.text();
  let data = null;
  if (tekst) {
    try {
      data = JSON.parse(tekst);
    } catch (e) {
      data = tekst;
    }
  }

  if (!response.ok) {
    const melding = typeof data === 'object' && data
      ? (data.message || data.error || JSON.stringify(data))
      : (data || response.statusText);
    throw new Error(melding);
  }

  return data;
}

async function laadStoringen() {
  const lokaal = leesJson(STORAGE_KEYS.storingen, []);

  try {
    const rijen = await supabaseRequest(`${SUPABASE_TABLE}?select=*&order=aangemaakt.desc`);
    const remote = Array.isArray(rijen) ? rijen.map(vanDb) : [];

    const alGemigreerd = localStorage.getItem(STORAGE_KEYS.migrated) === 'true';
    if (remote.length === 0 && lokaal.length > 0 && !alGemigreerd) {
      const gemigreerd = [];
      for (const item of lokaal) {
        const id = item.id || `${Date.now()}-${Math.random().toString(36).slice(2)}`;
        const aangemaakt = item.aangemaakt || new Date().toISOString();
        const payload = { id, aangemaakt, ...naarDb({ ...item, id, aangemaakt }) };
        const rows = await supabaseRequest(SUPABASE_TABLE, {
          method: 'POST',
          headers: { Prefer: 'return=representation' },
          body: JSON.stringify(payload),
        });
        gemigreerd.push(vanDb(rows[0]));
      }
      localStorage.setItem(STORAGE_KEYS.migrated, 'true');
      schrijfJson(STORAGE_KEYS.storingen, gemigreerd);
      return gemigreerd;
    }

    if (remote.length > 0) localStorage.setItem(STORAGE_KEYS.migrated, 'true');
    schrijfJson(STORAGE_KEYS.storingen, remote);
    return remote;
  } catch (e) {
    console.warn('Supabase kon niet geladen worden, lokale cache wordt gebruikt:', e);
    return lokaal;
  }
}

async function voegStoringToe(storing) {
  const lijst = await laadStoringen();
  const nieuw = {
    ...storing,
    id: storing.id || `${Date.now()}-${Math.random().toString(36).slice(2)}`,
    aangemaakt: storing.aangemaakt || new Date().toISOString(),
  };
  const rows = await supabaseRequest(SUPABASE_TABLE, {
    method: 'POST',
    headers: { Prefer: 'return=representation' },
    body: JSON.stringify({ id: nieuw.id, aangemaakt: nieuw.aangemaakt, ...naarDb(nieuw) }),
  });
  const opgeslagen = vanDb(rows[0]);
  const bijgewerkt = [opgeslagen, ...lijst];
  schrijfJson(STORAGE_KEYS.storingen, bijgewerkt);
  return opgeslagen;
}

async function werkStoringBij(id, storing) {
  const lijst = await laadStoringen();
  const bestaand = lijst.find(s => s.id === id) || {};
  const bijgewerktItem = { ...bestaand, ...storing, id };
  const rows = await supabaseRequest(`${SUPABASE_TABLE}?id=eq.${encodeURIComponent(id)}`, {
    method: 'PATCH',
    headers: { Prefer: 'return=representation' },
    body: JSON.stringify(naarDb(bijgewerktItem)),
  });
  const opgeslagen = rows && rows[0] ? vanDb(rows[0]) : bijgewerktItem;
  const bijgewerkt = lijst.map(s => s.id === id ? bijgewerktItem : s);
  schrijfJson(STORAGE_KEYS.storingen, bijgewerkt);
  return opgeslagen;
}

async function verwijderStoringDb(id) {
  const lijst = await laadStoringen();
  await supabaseRequest(`${SUPABASE_TABLE}?id=eq.${encodeURIComponent(id)}`, {
    method: 'DELETE',
  });
  schrijfJson(STORAGE_KEYS.storingen, lijst.filter(s => s.id !== id));
}

async function laadInstelling(id, standaard) {
  const instellingen = leesJson(STORAGE_KEYS.instellingen, {});
  return Object.prototype.hasOwnProperty.call(instellingen, id) ? instellingen[id] : standaard;
}

async function bewaarInstelling(id, waarde) {
  const instellingen = leesJson(STORAGE_KEYS.instellingen, {});
  instellingen[id] = waarde;
  schrijfJson(STORAGE_KEYS.instellingen, instellingen);
}

// =================== FACTUUR OPSLAG ===================
async function laadFactuurData() {
  const lokaalFacturen = leesJson(INVOICE_STORAGE_KEYS.invoices, []);
  const lokaalKlanten = leesJson(INVOICE_STORAGE_KEYS.customers, []);
  const lokaalBedrijf = leesJson(INVOICE_STORAGE_KEYS.company, DEFAULT_COMPANY);
  try {
    const [remoteFacturen, remoteKlanten, remoteBedrijf] = await Promise.all([
      supabaseRequest('invoices?select=*&order=created_at.desc'),
      supabaseRequest('customers?select=*&order=created_at.desc'),
      supabaseRequest('companies?select=*&limit=1'),
    ]);
    const facturen = Array.isArray(remoteFacturen) && remoteFacturen.length
      ? remoteFacturen.map(vanDbFactuur)
      : lokaalFacturen;
    const klanten = Array.isArray(remoteKlanten) && remoteKlanten.length
      ? remoteKlanten.map(vanDbKlant)
      : lokaalKlanten;
    const bedrijf = Array.isArray(remoteBedrijf) && remoteBedrijf[0]
      ? vanDbBedrijf(remoteBedrijf[0])
      : lokaalBedrijf;
    schrijfJson(INVOICE_STORAGE_KEYS.invoices, facturen);
    schrijfJson(INVOICE_STORAGE_KEYS.customers, klanten);
    schrijfJson(INVOICE_STORAGE_KEYS.company, bedrijf);
    return { facturen, klanten, bedrijf, online: true };
  } catch (e) {
    console.warn('Factuurdata lokaal geladen; Supabase-tabellen zijn mogelijk nog niet aangemaakt.', e);
    return { facturen: lokaalFacturen, klanten: lokaalKlanten, bedrijf: lokaalBedrijf, online: false };
  }
}

