async function arrayBufferToBase64(buffer) {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const chunkSize = 0x8000;
  for (let i = 0; i < bytes.length; i += chunkSize) {
    binary += String.fromCharCode(...bytes.subarray(i, i + chunkSize));
  }
  return btoa(binary);
}

async function setupPdfFont(doc) {
  const fontName = 'OverbetuweArial';
  try {
    const [regularRes, boldRes] = await Promise.all([
      fetch('/fonts/Arial.ttf'),
      fetch('/fonts/Arial-Bold.ttf'),
    ]);
    if (!regularRes.ok || !boldRes.ok) throw new Error('PDF font files unavailable');
    const [regular, bold] = await Promise.all([
      arrayBufferToBase64(await regularRes.arrayBuffer()),
      arrayBufferToBase64(await boldRes.arrayBuffer()),
    ]);
    doc.addFileToVFS('OverbetuweArial.ttf', regular);
    doc.addFont('OverbetuweArial.ttf', fontName, 'normal');
    doc.addFileToVFS('OverbetuweArial-Bold.ttf', bold);
    doc.addFont('OverbetuweArial-Bold.ttf', fontName, 'bold');
    doc.setFont(fontName, 'normal');
    return fontName;
  } catch (error) {
    console.warn('PDF lettertype kon niet worden geladen; standaardlettertype gebruikt.', error);
    return 'helvetica';
  }
}

async function imageToDataUrl(url) {
  if (!url) return '';
  if (String(url).startsWith('data:')) return url;
  const res = await fetch(url);
  if (!res.ok) return '';
  const blob = await res.blob();
  return await new Promise(resolve => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.readAsDataURL(blob);
  });
}

async function genereerFactuurPdf(factuur, bedrijf) {
  const { jsPDF } = await import('jspdf');
  const doc = new jsPDF({ unit: 'mm', format: 'a4', compress: true });
  const pdfFont = await setupPdfFont(doc);
  const W = 210, H = 297, margin = 10.8;
  const blue = [15, 45, 92], lightBlue = [30, 136, 229], paleBlue = [241, 247, 255], lineColor = [218, 226, 236], text = [24, 34, 48], muted = [92, 104, 122], gold = [255, 172, 0];
  const pdfEuro = cents => formatCurrencyNL(cents);
  const logo = (await imageToDataUrl('/overbetuwe-logo-pdf.png')) || (await imageToDataUrl(bedrijf.logoUrl || DEFAULT_COMPANY.logoUrl)) || LOGO_DATA_URL;
  const qr = await imageToDataUrl(DEFAULT_COMPANY.reviewQrUrl || bedrijf.reviewQrUrl);
  const totals = calculateInvoiceTotals(factuur.items || []);

  const imageType = (src) => String(src || '').toLowerCase().includes('png') ? 'PNG' : 'JPEG';
  const safe = value => String(value || '').trim();
  const split = (str, width) => doc.splitTextToSize(safe(str), width);
  const formatAddressParts = (...parts) => parts.map(safe).filter(Boolean).join(', ');
  const formatPostalCity = (postalCode, city) => [safe(postalCode), safe(city)].filter(Boolean).join(' ');
  const hLine = (y, strong = false) => {
    doc.setDrawColor(...(strong ? blue : lineColor));
    doc.setLineWidth(strong ? 0.42 : 0.22);
    doc.line(margin, y, W - margin, y);
  };
  const vLine = (x, y1, y2) => {
    doc.setDrawColor(...lineColor);
    doc.setLineWidth(0.22);
    doc.line(x, y1, x, y2);
  };
  const sectionIcon = (x, y, type = 'doc', subtle = false) => {
    const cy = y - 1.4;
    doc.setFillColor(...(subtle ? paleBlue : lightBlue));
    doc.circle(x, cy, 3.35, 'F');
    doc.setDrawColor(...(subtle ? blue : [255, 255, 255]));
    doc.setLineWidth(0.5);
    doc.setLineCap('round');
    doc.setLineJoin('round');
    if (type === 'person') {
      doc.circle(x, cy - 1.0, 0.82, 'S');
      doc.line(x - 1.65, cy + 1.85, x - 0.95, cy + 0.75);
      doc.line(x - 0.95, cy + 0.75, x + 0.95, cy + 0.75);
      doc.line(x + 0.95, cy + 0.75, x + 1.65, cy + 1.85);
    } else if (type === 'pin') {
      doc.circle(x, cy - 0.65, 0.75, 'S');
      doc.line(x, cy + 2.55, x - 1.45, cy + 0.35);
      doc.line(x, cy + 2.55, x + 1.45, cy + 0.35);
    } else if (type === 'bank') {
      doc.line(x - 2.0, cy - 1.05, x, cy - 2.25);
      doc.line(x, cy - 2.25, x + 2.0, cy - 1.05);
      doc.line(x - 1.95, cy + 1.75, x + 1.95, cy + 1.75);
      [-1.2, 0, 1.2].forEach(dx => doc.line(x + dx, cy - 0.7, x + dx, cy + 1.35));
    } else {
      doc.roundedRect(x - 1.55, cy - 2.0, 3.1, 4.15, 0.35, 0.35, 'S');
      doc.line(x - 0.8, cy - 0.45, x + 0.85, cy - 0.45);
      doc.line(x - 0.8, cy + 0.75, x + 0.85, cy + 0.75);
    }
    doc.setLineCap('butt');
    doc.setLineJoin('miter');
  };
  const smallIcon = (x, y, type = 'doc') => {
    doc.setDrawColor(...blue);
    doc.setLineWidth(0.42);
    doc.setLineCap('round');
    doc.setLineJoin('round');
    if (type === 'phone') {
      doc.line(x - 0.6, y - 1.3, x + 0.9, y + 0.2);
      doc.line(x - 1.0, y - 0.8, x - 0.55, y - 1.35);
      doc.line(x + 0.35, y + 0.6, x + 0.95, y + 0.1);
    } else if (type === 'pin') {
      doc.circle(x, y - 0.55, 0.62, 'S');
      doc.line(x, y + 1.2, x - 1.0, y - 0.15);
      doc.line(x, y + 1.2, x + 1.0, y - 0.15);
    } else if (type === 'mail') {
      doc.rect(x - 1.45, y - 1.2, 2.9, 2.1, 'S');
      doc.line(x - 1.45, y - 1.2, x, y + 0.1);
      doc.line(x + 1.45, y - 1.2, x, y + 0.1);
    } else if (type === 'web') {
      doc.circle(x, y - 0.2, 1.3, 'S');
      doc.line(x - 1.25, y - 0.2, x + 1.25, y - 0.2);
      doc.line(x, y - 1.5, x, y + 1.1);
    } else if (type === 'bank') {
      doc.line(x - 1.35, y - 0.6, x, y - 1.45);
      doc.line(x, y - 1.45, x + 1.35, y - 0.6);
      doc.line(x - 1.35, y + 1.0, x + 1.35, y + 1.0);
      [-0.75, 0, 0.75].forEach(dx => doc.line(x + dx, y - 0.35, x + dx, y + 0.75));
    } else {
      doc.roundedRect(x - 1.25, y - 1.45, 2.5, 2.75, 0.25, 0.25, 'S');
      doc.line(x - 0.65, y - 0.35, x + 0.65, y - 0.35);
      doc.line(x - 0.65, y + 0.55, x + 0.65, y + 0.55);
    }
    doc.setLineCap('butt');
    doc.setLineJoin('miter');
  };
  const drawStar = (cx, cy, r = 1.25) => {
    const pts = [];
    for (let i = 0; i < 10; i += 1) {
      const angle = -Math.PI / 2 + i * Math.PI / 5;
      const radius = i % 2 === 0 ? r : r * 0.45;
      pts.push([cx + Math.cos(angle) * radius, cy + Math.sin(angle) * radius]);
    }
    doc.setFillColor(...gold);
    const vectors = pts.slice(1).map((point, index) => [point[0] - pts[index][0], point[1] - pts[index][1]]);
    doc.lines(vectors, pts[0][0], pts[0][1], [1, 1], 'F', true);
  };
  const drawInlineText = (chunks, x, y, size = 8.6) => {
    let cursor = x;
    chunks.forEach(chunk => {
      const value = String(chunk.text || '');
      if (!value) return;
      doc.setFont(pdfFont, chunk.bold ? 'bold' : 'normal');
      doc.setFontSize(size);
      doc.setTextColor(...text);
      doc.text(value, cursor, y);
      cursor += doc.getTextWidth(value);
    });
  };
  const drawTableHeader = (headerY) => {
    doc.setFillColor(...blue);
    doc.roundedRect(margin, headerY, W - margin * 2, 9.2, 1.1, 1.1, 'F');
    doc.setFont(pdfFont, 'bold');
    doc.setFontSize(7.7);
    doc.setTextColor(255, 255, 255);
    doc.text('OMSCHRIJVING', cols[0] + 3, headerY + 6);
    doc.text('AANTAL', cols[2] - 4, headerY + 6, { align: 'right' });
    doc.text('EENHEID', cols[2] + 14, headerY + 6);
    doc.text('TARIEF EXCL. BTW', cols[4] - 4, headerY + 6, { align: 'right' });
    doc.text('TOTAAL EXCL. BTW', cols[5] - 3, headerY + 6, { align: 'right' });
  };
  const contactLine = (value, y, icon = 'doc') => {
    if (!safe(value)) return;
    smallIcon(136.6, y - 0.2, icon);
    doc.setFont(pdfFont, 'normal');
    doc.setFontSize(7.8);
    doc.setTextColor(...text);
    doc.text(safe(value), 141.2, y);
  };
  const footer = (page, total) => {
    hLine(H - 14, true);
    doc.setFont(pdfFont, 'bold');
    doc.setFontSize(8);
    doc.setTextColor(...blue);
    doc.text(safe(bedrijf.legalName || DEFAULT_COMPANY.legalName), margin, H - 8.5);
    doc.setFont(pdfFont, 'normal');
    doc.setFontSize(7.5);
    doc.setTextColor(...text);
    doc.text(`${safe(bedrijf.phone)}  -  ${safe(bedrijf.email)}  -  ${safe(bedrijf.website)}`, margin, H - 3.5);
    doc.setFontSize(8.2);
    doc.text(`Pagina ${page} van ${total}`, W - margin, H - 4.2, { align: 'right' });
  };

  if (logo) doc.addImage(logo, imageType(logo), margin, 10.5, 96, 29, undefined, 'NONE');
  doc.setFont(pdfFont, 'bold'); doc.setFontSize(8.8); doc.setTextColor(...blue);
  doc.text(safe(bedrijf.legalName || DEFAULT_COMPANY.legalName), 140, 13.5);
  const companyAddressLine = formatAddressParts(bedrijf.address, formatPostalCity(bedrijf.postalCode, bedrijf.city));
  [
    [companyAddressLine, 'pin'],
    [bedrijf.phone || DEFAULT_COMPANY.phone, 'phone'],
    [bedrijf.email || DEFAULT_COMPANY.email, 'mail'],
    [bedrijf.website || DEFAULT_COMPANY.website, 'web'],
    [`KvK ${bedrijf.kvkNumber || DEFAULT_COMPANY.kvkNumber}`, 'doc'],
    [`Btw ${bedrijf.vatNumber || DEFAULT_COMPANY.vatNumber}`, 'doc'],
    [`IBAN ${bedrijf.iban || DEFAULT_COMPANY.iban}`, 'bank'],
  ].filter(([line]) => safe(line)).forEach(([line, icon], index) => contactLine(line, 21 + index * 4.7, icon));
  hLine(55, true);
  doc.setFont(pdfFont, 'bold'); doc.setFontSize(29); doc.setTextColor(...blue); doc.text('FACTUUR', margin, 72);
  doc.setFontSize(8.8); doc.setTextColor(...text);
  const metaX = 132, metaY = 63;
  [['Factuurnummer:', factuur.invoiceNumber], ['Factuurdatum:', formatDateNl(factuur.invoiceDate)], ['Vervaldatum:', formatDateNl(factuur.dueDate)], ['Klantnummer:', factuur.customerNumber || factuur.customer?.customerNumber]].filter(r => safe(r[1])).forEach((r, i) => {
    doc.setFont(pdfFont, 'bold'); doc.text(r[0], metaX, metaY + i * 8);
    doc.setFont(pdfFont, 'normal'); doc.text(safe(r[1]), metaX + 39, metaY + i * 8);
  });
  hLine(89);
  sectionIcon(margin + 4, 101, 'person');
  doc.setFont(pdfFont, 'bold'); doc.setFontSize(9.2); doc.setTextColor(...blue); doc.text('FACTUUR AAN', margin + 11, 101);
  sectionIcon(106, 101, 'pin');
  doc.text('PROJECTGEGEVENS', 116, 101);
  vLine(96, 94, 134);
  doc.setFont(pdfFont, 'normal'); doc.setFontSize(8.8); doc.setTextColor(...text);
  [factuur.customer?.companyName || factuur.customer?.contactName, factuur.customer?.address, formatPostalCity(factuur.customer?.postalCode, factuur.customer?.city), factuur.customer?.phone, factuur.customer?.email].filter(Boolean).forEach((l, i) => {
    doc.setTextColor(...(String(l).includes('@') ? lightBlue : text));
    doc.text(split(l, 74), margin + 11, 112 + i * 7);
  });
  const uitvoering = factuur.project?.deliveryDateFrom === factuur.project?.deliveryDateTo ? formatLongDateNl(factuur.project?.deliveryDateFrom) : `${formatLongDateNl(factuur.project?.deliveryDateFrom)} t/m ${formatLongDateNl(factuur.project?.deliveryDateTo)}`;
  [['Werkadres:', formatAddressParts(factuur.project?.workAddress, factuur.project?.workCity)], ['Uitvoering:', uitvoering], ['Referentie:', factuur.project?.reference], ['Bijlage:', (factuur.photos || []).length > 0 ? `${(factuur.photos || []).length} foto${(factuur.photos || []).length === 1 ? '' : "'s"}` : '']].filter(r => safe(r[1])).forEach((r, i) => {
    doc.setFont(pdfFont, 'bold'); doc.setTextColor(...text); doc.text(r[0], 116, 112 + i * 9);
    doc.setFont(pdfFont, 'normal'); doc.text(split(r[1], 47), 141, 112 + i * 9);
  });
  hLine(141, true);
  sectionIcon(margin + 4, 153, 'doc');
  doc.setFont(pdfFont, 'bold'); doc.setFontSize(9.2); doc.setTextColor(...blue); doc.text('OMSCHRIJVING OPDRACHT', margin + 11, 153);
  const descriptionLines = split(factuur.project?.description || '-', 150);
  doc.setFont(pdfFont, 'normal'); doc.setFontSize(9); doc.setTextColor(...text); doc.text(descriptionLines, margin + 11, 158);
  const tableY = Math.max(168, 158 + descriptionLines.length * 4.6 + 7);
  const cols = [margin, 72, 100, 129, 167, W - margin];
  drawTableHeader(tableY);
  let y = tableY + 17;
  doc.setFont(pdfFont, 'normal'); doc.setFontSize(8.5); doc.setTextColor(...text);
  totals.lines.forEach(line => {
    const desc = split(line.description, 60);
    const rowH = Math.max(10.2, desc.length * 4.2 + 4);
    if (y + rowH > H - 35) {
      doc.addPage();
      drawTableHeader(24);
      y = 41;
      doc.setFont(pdfFont, 'normal');
      doc.setFontSize(8.5);
      doc.setTextColor(...text);
    }
    doc.text(desc, cols[0] + 3, y);
    doc.text(String(line.quantity).replace('.', ','), cols[2] - 8, y, { align: 'right' });
    doc.text(line.unit, cols[2] + 18, y, { align: 'center' });
    doc.text(pdfEuro(line.unitPriceExVatCents), cols[4] - 4, y, { align: 'right' });
    doc.text(pdfEuro(line.lineSubtotalCents), cols[5] - 5, y, { align: 'right' });
    hLine(y + rowH - 5);
    [cols[1], cols[2], cols[3], cols[4]].forEach(x => vLine(x, y - 7.5, y + rowH - 5));
    y += rowH;
  });
  const tableBottomY = y - 5;
  const footerSafeY = H - 13;
  const totalBoxH = 30;
  const reviewBoxH = 23;
  const lowerBlocksH = Math.max(28, totalBoxH + 6 + reviewBoxH) + 4;
  const maxLowerY = footerSafeY - lowerBlocksH;
  let lowerY = Math.min(tableBottomY + 8, maxLowerY);
  if (tableBottomY > maxLowerY + 12) {
    doc.addPage();
    lowerY = 24;
  }
  const payY = lowerY;
  sectionIcon(margin + 5, payY + 16, 'bank');
  const payX = margin + 17;
  const payAmount = pdfEuro(totals.totalIncVatCents);
  const payDate = formatLongDateNl(factuur.dueDate);
  const payIban = bedrijf.iban || DEFAULT_COMPANY.iban;
  drawInlineText([{ text: 'Wij verzoeken u het totaalbedrag van ' }], payX, payY + 8.5);
  drawInlineText([{ text: payAmount, bold: true }, { text: ' uiterlijk op ' }, { text: payDate, bold: true }], payX, payY + 14);
  drawInlineText([{ text: 'over te maken naar IBAN ' }, { text: payIban, bold: true }, { text: ',' }], payX, payY + 19.5);
  drawInlineText([{ text: 'onder vermelding van factuurnummer ' }, { text: factuur.invoiceNumber, bold: true }, { text: '.' }], payX, payY + 25);

  const boxX = 109, boxY = lowerY;
  doc.setDrawColor(...lineColor); doc.setFillColor(250, 252, 255);
  doc.roundedRect(boxX, boxY, 90, 30, 2, 2, 'FD');
  doc.setFont(pdfFont, 'normal'); doc.setFontSize(8.8); doc.setTextColor(...text);
  doc.text('Subtotaal exclusief btw', boxX + 7, boxY + 9); doc.text(pdfEuro(totals.subtotalExVatCents), boxX + 83, boxY + 9, { align: 'right' });
  totals.vatBreakdown.forEach((vat, i) => {
    const label = vat.vatRate === 'verlegd' ? 'Btw verlegd' : `Btw ${vat.vatRate}%`;
    doc.text(label, boxX + 7, boxY + 18 + i * 6);
    doc.text(pdfEuro(vat.vatCents), boxX + 83, boxY + 18 + i * 6, { align: 'right' });
  });
  doc.setDrawColor(...lightBlue); doc.setLineWidth(0.35); doc.line(boxX, boxY + 21.2, boxX + 90, boxY + 21.2);
  doc.setFillColor(...paleBlue); doc.rect(boxX + 0.2, boxY + 21.7, 89.6, 8.1, 'F');
  doc.setFont(pdfFont, 'bold'); doc.setTextColor(...blue); doc.setFontSize(8.8);
  doc.text('TOTAAL INCLUSIEF BTW', boxX + 7, boxY + 27.3);
  doc.setFontSize(14); doc.text(pdfEuro(totals.totalIncVatCents), boxX + 83, boxY + 27.6, { align: 'right' });

  const reviewY = boxY + totalBoxH + 6;
  doc.setDrawColor(...lineColor); doc.setFillColor(255, 255, 255);
  doc.roundedRect(boxX, reviewY, 90, 23, 2, 2, 'FD');
  doc.setFont(pdfFont, 'bold'); doc.setFontSize(8.8); doc.setTextColor(...blue);
  doc.text('Laat een Google review achter', boxX + 5.5, reviewY + 8);
  doc.setFont(pdfFont, 'normal'); doc.setFontSize(7.6); doc.setTextColor(...text);
  doc.text('Uw mening wordt zeer gewaardeerd', boxX + 5.5, reviewY + 13.8);
  [0, 1, 2, 3, 4].forEach(i => drawStar(boxX + 7 + i * 5.2, reviewY + 19, 1.25));
  doc.setDrawColor(...lineColor); doc.line(boxX + 59, reviewY + 3, boxX + 59, reviewY + 20);
  if (qr) doc.addImage(qr, imageType(qr), boxX + 64, reviewY + 1.1, 21.8, 21.8, undefined, 'NONE');

  const termsY = Math.min(reviewY + reviewBoxH + 6, H - 21);
  sectionIcon(margin + 5, termsY - 1.2, 'doc', true);
  doc.setFont(pdfFont, 'normal'); doc.setFontSize(6.5); doc.setTextColor(...muted);
  doc.text(split(bedrijf.footerText || DEFAULT_COMPANY.footerText, 88), margin + 12, termsY);
  // Footers are drawn after all pages exist so the total page count is exact.

  const photos = [...(factuur.photos || [])].sort((a, b) => (a.sortOrder || 0) - (b.sortOrder || 0));
  for (let p = 0; p < Math.ceil(photos.length / 6); p++) {
    doc.addPage();
    if (logo) doc.addImage(logo, imageType(logo), margin, 12, 72, 22, undefined, 'NONE');
    doc.setFont(pdfFont, 'bold'); doc.setFontSize(20); doc.setTextColor(...blue); doc.text('FOTOBIJLAGE', margin, 48);
    doc.setFont(pdfFont, 'normal'); doc.setFontSize(9); doc.setTextColor(...text);
    doc.text(`Factuurnummer: ${factuur.invoiceNumber}`, margin, 58);
    doc.text(`Referentie: ${factuur.project?.reference || '-'}`, margin, 64);
    doc.text(`Werkadres: ${factuur.project?.workAddress || ''}, ${factuur.project?.workCity || ''}`, margin, 70);
    doc.text('Onderstaande foto\'s geven een overzicht van de uitgevoerde werkzaamheden.', margin, 78);
    const subset = photos.slice(p * 6, p * 6 + 6);
    for (let i = 0; i < subset.length; i++) {
      const col = i % 3, row = Math.floor(i / 3);
      const x = margin + col * 62, yy = 88 + row * 78;
      const photo = subset[i];
      if (photo.src) doc.addImage(photo.src, imageType(photo.src), x, yy, 56, 44, undefined, 'FAST');
      doc.setFillColor(...blue); doc.circle(x + 5, yy + 5, 4, 'F'); doc.setTextColor(255,255,255); doc.setFont(pdfFont,'bold'); doc.setFontSize(7); doc.text(String(p * 6 + i + 1), x + 5, yy + 7, { align: 'center' });
      doc.setTextColor(...text); doc.setFont(pdfFont,'bold'); doc.text(photo.category || 'Overig', x, yy + 51);
      doc.setFont(pdfFont,'normal'); doc.text(split(photo.caption || '', 54), x, yy + 57);
    }
  }

  const totalPages = doc.getNumberOfPages();
  for (let pageNo = 1; pageNo <= totalPages; pageNo += 1) {
    doc.setPage(pageNo);
    footer(pageNo, totalPages);
  }

  const blob = doc.output('blob');
  const dataUrl = doc.output('datauristring');
  return { blob, dataUrl };
}

function downloadBlob(blob, name) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = name; document.body.appendChild(a); a.click(); a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

// =================== INSTELLINGEN ===================
function Instellingen() {
  const [tarieven, setTarieven] = useState(() => PRIJSLIJST.map(p => ({ ...p })));
  const [opgeslagen, setOpgeslagen] = useState(false);
  const [bezig, setBezig] = useState(false);

  // BTW-percentage (21%) - om automatisch excl. uit incl. te berekenen
  const BTW = 0.21;

  const updateTarief = (id, veld, waarde) => {
    setOpgeslagen(false);
    setTarieven(t => t.map(item => {
      if (item.id !== id) return item;
      const num = parseFloat(waarde) || 0;
      if (veld === 'tariefIncl') {
        return { ...item, tariefIncl: num, tariefExcl: Math.round((num / (1 + BTW)) * 100) / 100 };
      } else {
        return { ...item, tariefExcl: num, tariefIncl: Math.round((num * (1 + BTW)) * 100) / 100 };
      }
    }));
  };

  const opslaan = async () => {
    setBezig(true);
    try {
      await bewaarInstelling('tarieven', tarieven);
      // Update de runtime PRIJSLIJST direct
      tarieven.forEach(t => {
        const item = PRIJSLIJST.find(p => p.id === t.id);
        if (item) {
          item.tariefIncl = t.tariefIncl;
          item.tariefExcl = t.tariefExcl;
        }
      });
      setOpgeslagen(true);
      setTimeout(() => setOpgeslagen(false), 3000);
    } catch (e) {
      alert('Opslaan mislukt: ' + e.message);
    }
    setBezig(false);
  };

  const herstelStandaard = () => {
    if (confirm('Standaardtarieven herstellen? De huidige bedragen worden overschreven.')) {
      setTarieven(PRIJSLIJST_STANDAARD.map(p => ({ ...p })));
      setOpgeslagen(false);
    }
  };

  return (
    <div style={{ padding: 16, maxWidth: 700, margin: '0 auto' }}>
      <h2 style={{ color: COLORS.blue, fontSize: 22, fontWeight: 800, margin: '0 0 8px' }}>Instellingen</h2>
      <p style={{ color: COLORS.textLight, fontSize: 13, marginBottom: 20 }}>
        Pas de tarieven aan voor de prijsberekening bij particuliere klussen.
      </p>

      <div style={{ background: COLORS.white, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: 16, marginBottom: 16 }}>
        <h3 style={{ color: COLORS.blue, fontSize: 16, fontWeight: 700, margin: '0 0 12px' }}>Tarieven (per uur)</h3>

        {tarieven.map(t => (
          <div key={t.id} style={{ marginBottom: 14, paddingBottom: 14, borderBottom: `1px solid ${COLORS.border}` }}>
            <div style={{ fontWeight: 600, fontSize: 14, color: COLORS.text, marginBottom: 6 }}>{t.label}</div>
            <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
              <div style={{ flex: 1, minWidth: 140 }}>
                <label style={{ fontSize: 11, color: COLORS.textLight, fontWeight: 600, display: 'block', marginBottom: 3 }}>Excl. BTW</label>
                <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                  <span style={{ fontSize: 14, color: COLORS.textLight }}>EUR</span>
                  <input
                    type="number"
                    step="0.01"
                    min="0"
                    value={t.tariefExcl}
                    onChange={e => updateTarief(t.id, 'tariefExcl', e.target.value)}
                    style={{ flex: 1, padding: '8px 10px', border: `1px solid ${COLORS.border}`, borderRadius: 6, fontSize: 14, background: COLORS.white, color: COLORS.text }}
                  />
                </div>
              </div>
              <div style={{ flex: 1, minWidth: 140 }}>
                <label style={{ fontSize: 11, color: COLORS.textLight, fontWeight: 600, display: 'block', marginBottom: 3 }}>Incl. BTW (21%)</label>
                <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                  <span style={{ fontSize: 14, color: COLORS.textLight }}>EUR</span>
                  <input
                    type="number"
                    step="0.01"
                    min="0"
                    value={t.tariefIncl}
                    onChange={e => updateTarief(t.id, 'tariefIncl', e.target.value)}
                    style={{ flex: 1, padding: '8px 10px', border: `2px solid ${COLORS.yellow}`, borderRadius: 6, fontSize: 14, fontWeight: 600, background: COLORS.white, color: COLORS.text }}
                  />
                </div>
              </div>
            </div>
          </div>
        ))}

        <p style={{ fontSize: 11, color: COLORS.textLight, fontStyle: 'italic', margin: '8px 0' }}>
          Tip: vul een bedrag in (excl. of incl.), de andere wordt automatisch berekend.
        </p>

        <div style={{ display: 'flex', gap: 8, marginTop: 16, flexWrap: 'wrap' }}>
          <button
            onClick={opslaan}
            disabled={bezig}
            style={{ flex: 2, minWidth: 140, padding: '12px', background: COLORS.yellow, color: COLORS.blue, border: 'none', borderRadius: 8, fontWeight: 700, cursor: bezig ? 'wait' : 'pointer', fontSize: 15 }}
          >
            {bezig ? 'Bezig...' : opgeslagen ? 'Opgeslagen' : 'Tarieven opslaan'}
          </button>
          <button
            onClick={herstelStandaard}
            style={{ flex: 1, minWidth: 140, padding: '12px', background: COLORS.white, color: COLORS.text, border: `1px solid ${COLORS.border}`, borderRadius: 8, fontWeight: 600, cursor: 'pointer', fontSize: 14 }}
          >
            Standaard herstellen
          </button>
        </div>
      </div>

      <div style={{ background: COLORS.white, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: 16, marginBottom: 16 }}>
        <h3 style={{ color: COLORS.blue, fontSize: 16, fontWeight: 700, margin: '0 0 8px' }}>Informatie</h3>
        <p style={{ fontSize: 13, color: COLORS.textLight, margin: '0 0 8px' }}>
          <strong>Weekendtarief</strong> wordt automatisch toegepast van vrijdag 18:00 tot maandag 06:00.
        </p>
        <p style={{ fontSize: 13, color: COLORS.textLight, margin: '0 0 8px' }}>
          <strong>BTW</strong> staat ingesteld op 21% (Nederlands hoog tarief).
        </p>
        <p style={{ fontSize: 13, color: COLORS.textLight, margin: '0' }}>
          Tariefwijzigingen worden direct doorgevoerd in de app.
        </p>
      </div>
    </div>
  );
}
